from flask import Blueprint, request, jsonify
from flask_login import login_required, current_user
from functools import wraps

profile_bp = Blueprint('profile', __name__)

def admin_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if not current_user.is_authenticated or current_user.role != 'admin':
            return jsonify({'error': 'Admin access required'}), 403
        return f(*args, **kwargs)
    return decorated_function

@profile_bp.route('/api/profile', methods=['PUT', 'PATCH'])
@login_required
def update_profile():
    from models import db, User
    
    data = request.get_json()
    
    if not data:
        return jsonify({'error': 'No data provided'}), 400
    
    user = User.query.filter_by(id=current_user.id).first()
    
    if not user:
        return jsonify({'error': 'User not found'}), 404
    
    if user.id != current_user.id:
        return jsonify({'error': 'Unauthorized'}), 403
    
    regular_user_fields = ['email', 'username', 'referral_code']
    admin_only_fields = ['account_type', 'credits', 'verified_status']
    
    updated_fields = []
    
    for field in regular_user_fields:
        if field in data:
            if field == 'email':
                email = data['email']
                if not email or '@' not in email:
                    return jsonify({'error': 'Invalid email format'}), 400
                existing = User.query.filter_by(email=email).first()
                if existing and existing.id != user.id:
                    return jsonify({'error': 'Email already in use'}), 400
                user.email = email
                updated_fields.append(field)
            elif field == 'username':
                username = data['username']
                if not username or len(username) < 3:
                    return jsonify({'error': 'Username must be at least 3 characters'}), 400
                existing = User.query.filter_by(username=username).first()
                if existing and existing.id != user.id:
                    return jsonify({'error': 'Username already taken'}), 400
                user.username = username
                updated_fields.append(field)
            elif field == 'referral_code':
                user.referral_code = data['referral_code']
                updated_fields.append(field)
    
    for field in admin_only_fields:
        if field in data:
            if current_user.role != 'admin':
                return jsonify({'error': f'Admin access required to update {field}'}), 403
            
            if field == 'account_type':
                allowed_types = ['free', 'premium', 'enterprise']
                if data['account_type'] not in allowed_types:
                    return jsonify({'error': f'Invalid account_type. Must be one of {allowed_types}'}), 400
                user.account_type = data['account_type']
                updated_fields.append(field)
            elif field == 'credits':
                if not isinstance(data['credits'], (int, float)) or data['credits'] < 0:
                    return jsonify({'error': 'Credits must be a non-negative number'}), 400
                user.credits = data['credits']
                updated_fields.append(field)
            elif field == 'verified_status':
                if not isinstance(data['verified_status'], bool):
                    return jsonify({'error': 'verified_status must be a boolean'}), 400
                user.verified_status = data['verified_status']
                updated_fields.append(field)
    
    if not updated_fields:
        return jsonify({'error': 'No valid fields to update'}), 400
    
    try:
        db.session.commit()
        
        return jsonify({
            'message': 'Profile updated successfully',
            'updated_fields': updated_fields,
            'user': {
                'id': user.id,
                'email': user.email,
                'username': user.username,
                'account_type': user.account_type,
                'credits': user.credits,
                'referral_code': user.referral_code,
                'verified_status': user.verified_status
            }
        }), 200
    except Exception as e:
        db.session.rollback()
        return jsonify({'error': 'Failed to update profile'}), 500